#define EQUATIONS 91
#endif

#ifndef PARAMETERS
#define PARAMETERS 18
#endif

#define max(x,y) ( (x) < (y) ? (y) : (x) )
#define min(x,y) ( (x) < (y) ? (x) : (y) )

#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125f
#define MAX_SCALE_FACTOR 4.0f

extern void read(char* filename, fp* input, int data_rows, int data_cols, int major);
extern long long get_time(void);

extern void embedded_fehlberg_7_8(fp timeinst,
                                  fp h,
                                  fp* initvalu,
                                  fp* finavalu,
                                  fp* error,
                                  fp* parameter,
                                  fp* com,
                                  fp* d_initvalu,
                                  fp* d_finavalu,
                                  fp* d_params,
                                  fp* d_com);

static void solver_2_cpu(int workload, int xmax, fp* x, fp* y, fp* params) {
    #pragma omp parallel for schedule(static)
    for (int tid = 0; tid < workload; tid++) {
        fp err_exponent = 1.0f / 7.0f;
        fp h_init = 1.0f;
        fp h = h_init;
        int xmin = 0;
        fp tolerance = 10.0f / (fp)(xmax - xmin);

        fp* err = (fp*)malloc(EQUATIONS * sizeof(fp));
        fp* scale = (fp*)malloc(EQUATIONS * sizeof(fp));
        fp* yy = (fp*)malloc(EQUATIONS * sizeof(fp));
        fp com[3] = {0.0f, 0.0f, 0.0f};

        int params_pointer = tid * PARAMETERS;

        if (xmax < xmin || h <= 0.0f){
            free(err); free(scale); free(yy);
            continue;
        }

        if (xmax == xmin){
            free(err); free(scale); free(yy);
            continue;
        }

        if (h > (xmax - xmin)) {
            h = (fp)xmax - (fp)xmin;
        }

        for(int k=1; k<(xmax+1); k++) {
            long y_pointer_initial = (long)tid*((xmax+1)*EQUATIONS)+(long)(k-1)*EQUATIONS;
            long y_pointer_current = (long)tid*((xmax+1)*EQUATIONS)+(long)k*EQUATIONS;
            long x_pointer_current = (long)tid*(xmax+1)+k;

            x[x_pointer_current] = (fp)k;
            h = h_init;

            fp scale_fina = 1.0f;
            int j;

            for (j = 0; j < ATTEMPTS; j++) {
                int error = 0;
                int outside = 0;
                fp scale_min = MAX_SCALE_FACTOR;

                embedded_fehlberg_7_8(h,
                                      x[x_pointer_current],
                                      &y[y_pointer_initial],
                                      &y[y_pointer_current],
                                      err,
                                      &params[params_pointer],
                                      com,
                                      NULL, NULL, NULL, NULL);

                for(int i=0; i<EQUATIONS; i++){
                    if(err[i] > 0){
                        error = 1;
                    }
                }
                if (error != 1) {
                    scale_fina = MAX_SCALE_FACTOR;
                    break;
                }

                for(int i=0; i<EQUATIONS; i++){
                    if(y[y_pointer_initial+i] == 0.0f){
                        yy[i] = tolerance;
                    }
                    else{
                        yy[i] = fabsf(y[y_pointer_initial+i]);
                    }
                    scale[i] = 0.8f * powf(tolerance * yy[i] / err[i], err_exponent);
                    if(scale[i] < scale_min){
                        scale_min = scale[i];
                    }
                }
                scale_fina = min(max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

                for(int i=0; i<EQUATIONS; i++){
                    if ( err[i] > ( tolerance * yy[i] ) ){
                        outside = 1;
                    }
                }
                if (outside == 0){
                    break;
                }

                h = h * scale_fina;

                if (h >= 0.9f) {
                    h = 0.9f;
                }

                if ( x[x_pointer_current] + h > (fp)xmax ){
                    h = (fp)xmax - x[x_pointer_current];
                }
                else if ( x[x_pointer_current] + h + 0.5f * h > (fp)xmax ){
                    h = 0.5f * h;
                }
            }

            x[x_pointer_current] = x[x_pointer_current] + h;

            if ( j >= ATTEMPTS ) {
                break;
            }
        }

        free(err);
        free(scale);
        free(yy);
    }
}

